import {
  buildTenantRequestHeaders,
  getAuthToken,
  ApiConnectionError,
  classifyApiConnectionFailure,
  deriveHealthUrlFromApiBase,
  getApiConnectionOpsMessage,
  redirectToLoginAfterAuthFailure,
} from '@linm-soft-org/linm-web-common-components';
import { getApiNavigationHandler } from '../utils/apiErrorNavigation';

const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:5000/api';

/** True for login/logout/refresh endpoints — must not trigger silent refresh. */
function isAuthSelfRequestUrl(url: string): boolean {
  const segments = ['/auth/login', '/auth/logout', '/auth/refresh-token'];
  try {
    const path = new URL(url, typeof window !== 'undefined' ? window.location.origin : 'http://localhost').pathname;
    return segments.some((segment) => path.includes(segment));
  } catch {
    return false;
  }
}

export interface ApiError {
  message: string;
  statusCode: number;
  errors?: Record<string, string[]>;
}

class ApiClient {
  private baseURL: string;

  constructor(baseURL: string) {
    this.baseURL = baseURL;
  }

  private async request<T>(
    endpoint: string,
    options: RequestInit = {},
  ): Promise<T> {
    const url = `${this.baseURL}${endpoint}`;
    const method = (options.method || 'GET').toUpperCase();

    const headers: Record<string, string> = {
      ...buildTenantRequestHeaders(options.headers as Record<string, string> || {}),
    };

    const token = getAuthToken();
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    try {
      const response = await fetch(url, {
        ...options,
        headers,
      });

      if (!response.ok) {
        if (response.status === 401 && !isAuthSelfRequestUrl(url)) {
          if (!getAuthToken()) {
            redirectToLoginAfterAuthFailure();
          }
          throw new Error('Phiên đăng nhập hết hạn. Vui lòng đăng nhập lại.');
        }

        // Dispatch global navigation for 403 / 404 — CHỈ GET (load page)
        if ((response.status === 404 || response.status === 403) && method === 'GET') {
          const handler = getApiNavigationHandler();
          if (handler) {
            handler({ statusCode: response.status, endpoint, method });
            throw new Error(response.status === 404 ? 'Không tìm thấy' : 'Không có quyền truy cập');
          }
        }

        let errorMessage = 'API request failed';
        try {
          const errorBody = await response.json();
          errorMessage =
            errorBody?.error?.toastMessage ||
            errorBody?.message ||
            errorBody?.title ||
            errorMessage;
        } catch {
          // ignore JSON parse errors on error body
        }
        throw new Error(errorMessage);
      }

      if (response.status === 204) {
        return undefined as unknown as T;
      }

      return await response.json();
    } catch (error) {
      if (error instanceof TypeError && error.message === 'Failed to fetch') {
        const kind = await classifyApiConnectionFailure(this.baseURL);
        const opsHint = getApiConnectionOpsMessage(kind);
        console.warn(
          '[API] Connection failure — kind=%s ops=%s endpoint=%s health=%s',
          kind,
          opsHint,
          endpoint,
          deriveHealthUrlFromApiBase(this.baseURL),
        );
        throw new ApiConnectionError(kind);
      }
      console.error('API request error:', error);
      throw error;
    }
  }

  async get<T>(endpoint: string): Promise<T> {
    return this.request<T>(endpoint, { method: 'GET' });
  }

  async post<T>(endpoint: string, data?: unknown): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'POST',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  async put<T>(endpoint: string, data?: unknown): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'PUT',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  async patch<T>(endpoint: string, data?: unknown): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'PATCH',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  async delete<T>(endpoint: string, data?: unknown): Promise<T> {
    return this.request<T>(endpoint, {
      method: 'DELETE',
      body: data ? JSON.stringify(data) : undefined,
    });
  }

  async postBlob(endpoint: string, data?: unknown): Promise<Blob> {
    const url = `${this.baseURL}${endpoint}`;
    const headers: Record<string, string> = {
      ...buildTenantRequestHeaders(),
    };
    const token = getAuthToken();
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const response = await fetch(url, {
      method: 'POST',
      headers,
      body: data ? JSON.stringify(data) : undefined,
    });

    if (!response.ok) {
      let errorMessage = 'Export thất bại';
      try {
        const errorBody = await response.json();
        errorMessage = errorBody?.error?.toastMessage || errorBody?.message || errorMessage;
      } catch { /* ignore */ }
      throw new Error(errorMessage);
    }

    return response.blob();
  }

  async getBlob(endpoint: string): Promise<Blob> {
    const url = `${this.baseURL}${endpoint}`;
    const headers: Record<string, string> = {
      ...buildTenantRequestHeaders(),
    };
    const token = getAuthToken();
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const response = await fetch(url, { method: 'GET', headers });

    if (!response.ok) {
      let errorMessage = 'Tải file thất bại';
      try {
        const errorBody = await response.json();
        errorMessage = errorBody?.error?.toastMessage || errorBody?.message || errorMessage;
      } catch { /* ignore */ }
      throw new Error(errorMessage);
    }

    return response.blob();
  }
}

export const apiClient = new ApiClient(API_BASE_URL);

export function unwrap<T>(response: { data?: T; error?: unknown }): T {
  if (response.error) {
    const msg =
      (response.error as { toastMessage?: string })?.toastMessage ||
      (response.error as { message?: string })?.message ||
      'API error';
    throw new Error(msg);
  }
  return response.data as T;
}

export type { BffResponse } from '@linm-soft-org/linm-web-common-components';
